public void testProcessClosurePrimitivesWithRequire() {
  test("var goog = {}; goog.require('goog.dom');",
       "var goog = {};");
  args.add("--process_closure_primitives=false");
  testSame("var goog = {}; goog.require('goog.dom');");
}

public void testProcessClosurePrimitivesExplicitTrue() {
  args.add("--process_closure_primitives=true");
  test("var goog = {}; goog.provide('goog.ui');",
       "var goog = {}; goog.ui = {};");
}
